#!/bin/bash
# ============================================
# literature-review 一键部署脚本（自包含，无需 GitHub）
# 在腾讯云 WebShell 中执行: bash deploy-literature-review.sh
# ============================================
set -e
GREEN='\033[0;32m'; YELLOW='\033[1;33m'; NC='\033[0m'
echo -e "${GREEN}========================================${NC}"
echo -e "${GREEN}  literature-review 自包含部署${NC}"
echo -e "${GREEN}========================================${NC}"

INSTALL_DIR="/opt/literature-review"
mkdir -p "$INSTALL_DIR/assets" "$INSTALL_DIR/references" "$INSTALL_DIR/scripts"
cd "$INSTALL_DIR"

echo -e "${YELLOW}[1/2] 写入文件...${NC}"
echo '' | base64 -d > "SKILL.md"
echo '' | base64 -d > "assets/review_template.md"
echo '' | base64 -d > "references/citation_styles.md"
echo '' | base64 -d > "references/database_strategies.md"
echo '' | base64 -d > "scripts/generate_pdf.py"
echo '' | base64 -d > "scripts/search_databases.py"
echo '' | base64 -d > "scripts/verify_citations.py"

echo -e "${GREEN}文件写入完成 ✓${NC}"
echo ""
ls -la "$INSTALL_DIR"
echo ""
echo -e "${GREEN}========================================${NC}"
echo -e "${GREEN}  部署完成！${NC}"
echo -e "${GREEN}========================================${NC}"
echo ""
echo "文件位置: /opt/literature-review"
echo "使用: 将该目录链接到 CodeBuddy skills 目录"
